		SessionID:   "session-1",
		SessionDir:  sessionDir,
		SessionPath: sessionPath,
	}}
	done := make(chan struct{})
	go func() {
		defer close(done)
		time.Sleep(25 * time.Millisecond)
		file, err := os.OpenFile(sessionPath, os.O_APPEND|os.O_WRONLY, 0o644)
		if err != nil {
			return
		}
		defer file.Close()
