	evidence, ok, err := terminalEvidenceForActiveChildWithRefresh(state)
	<-done
	if err != nil || !ok || !evidence.ContextWindowError || evidence.Line != 3 {
		t.Fatalf("evidence=%+v ok=%v err=%v", evidence, ok, err)
